package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.LooncodeInclusief;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.jpa.gl.LooncodeInclusiefPK;
import be.schaubroeck.lpb.tools.service.LooncodeInclusiefService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import com.google.common.collect.ArrayListMultimap;
import com.google.common.collect.ListMultimap;
import lombok.Data;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.List;

public class CachedLooncodeInclusiefService implements CachedService, LooncodeInclusiefService {

    @Autowired
    private LooncodeInclusiefService looncodeInclusiefService;

    private static final ThreadLocal<CachedLooncodeInclusiefBuffer> BUFFER = new ThreadLocal<>();

    public CachedLooncodeInclusiefService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public List<LooncodeInclusief> findByTijdperkAke(Integer tijdperk, Integer aard, Integer code, Integer extensie) {
        TimeLogContext.getInstance().startTimeLogging("CachedLooncodeInclusiefService.findByTijdperkAke");
        CachedLooncodeInclusiefBuffer buffer = CachedLooncodeInclusiefService.getBuffer();
        AardKodeExtensieKey key = new AardKodeExtensieKey(tijdperk, aard, code, extensie);
        List<LooncodeInclusief> result;
        if (!buffer.containsKey(key)) {
            result = looncodeInclusiefService.findByTijdperkAke(tijdperk, aard, code, extensie);
            buffer.put(key, result);
        } else {
            result = buffer.get(key);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public List<LooncodeInclusief> findByAardKodeExtensie(AardKodeExtensie aardKodeExtensie) {
        return findByTijdperkAke(aardKodeExtensie.getTijdperk(), aardKodeExtensie.getAard(), aardKodeExtensie.getCode(),
                aardKodeExtensie.getExtensie());
    }

    @Override
    public void clearCache() {
        CachedLooncodeInclusiefService.getBuffer().clear();
    }

    private static class CachedLooncodeInclusiefBuffer {

        private final ListMultimap<AardKodeExtensieKey, LooncodeInclusief> aardKodeExtensieBuffer = ArrayListMultimap.create();

        public List<LooncodeInclusief> get(AardKodeExtensieKey key) {
            return aardKodeExtensieBuffer.get(key);
        }

        public void put(AardKodeExtensieKey key, List<LooncodeInclusief> lijst) {
            aardKodeExtensieBuffer.putAll(key, lijst);
        }

        public boolean containsKey(AardKodeExtensieKey key) {
            return aardKodeExtensieBuffer.containsKey(key);
        }

        public void clear() {
            aardKodeExtensieBuffer.clear();
        }
    }

    private static CachedLooncodeInclusiefBuffer getBuffer() {
        CachedLooncodeInclusiefBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedLooncodeInclusiefBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Data
    private static class AardKodeExtensieKey {

        private final int tijdperk;
        private final int aard;
        private final int code;
        private final int extensie;
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public List<LooncodeInclusief> findAll() {
        return looncodeInclusiefService.findAll();
    }

    @Override
    public LooncodeInclusief create(LooncodeInclusief constant) {
        return looncodeInclusiefService.create(constant);
    }

    @Override
    public LooncodeInclusief update(LooncodeInclusief constant) {
        return looncodeInclusiefService.update(constant);
    }

    @Override
    public void delete(LooncodeInclusief constant) {
        looncodeInclusiefService.delete(constant);
    }

    @Override
    public LooncodeInclusief getById(LooncodeInclusiefPK id) {
        return looncodeInclusiefService.getById(id);
    }

    @Override
    public LooncodeInclusief getById(LooncodeInclusiefPK id, String fetchFields) {
        return looncodeInclusiefService.getById(id, fetchFields);
    }


    @Override
    public LooncodeInclusief getByCriteria(CriteriaBuilder cb) {
        return looncodeInclusiefService.getByCriteria(cb);
    }


    @Override
    public List<LooncodeInclusief> findAll(String fetchFields) {
        return looncodeInclusiefService.findAll(fetchFields);
    }

    @Override
    public List<LooncodeInclusief> findByCriteria(CriteriaBuilder cb) {
        return looncodeInclusiefService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return looncodeInclusiefService.countByCriteria(cb);
    }


}
